outbound.log-to-eventhub:
@{
      var usage = context.Response.Body?.As(preserveContent: true)?["usage"];
      return new JObject(
        new JProperty("ts", DateTime.UtcNow.ToString("o")),
        new JProperty("subscriptionId", context.Subscription.Id),
        new JProperty("tenant", context.Request.Headers.GetValueOrDefault("x-tf-tenant", "unknown")),
        new JProperty("route", context.Request.Headers.GetValueOrDefault("x-tf-route", "unknown")),
        new JProperty("requestId", context.RequestId),
        new JProperty("region", context.Deployment.Region),
        new JProperty("promptTokens", (int?)(usage?["prompt_tokens"]) ?? 0),
        new JProperty("completionTokens", (int?)(usage?["completion_tokens"]) ?? 0),
        new JProperty("cachedTokens", (int?)(usage?["prompt_tokens_details"]?["cached_tokens"]) ?? 0)
      ).ToString();
    }
